const filename = msg.filename;
const srcTopic = msg.source_topic;
const ts = msg.ingest_timestamp;
let parsed;
try {
    const text = msg.content.toString('utf8');
    parsed = JSON.parse(text);
} catch (e) {
    return [null, { payload: {
        error_type: 'parse',
        error_message: 'json: ' + e.message,
        error_timestamp: new Date().toISOString(),
        filename: filename,
        source_topic: srcTopic
    }, filename: filename }];
}
const records = Array.isArray(parsed) ? parsed : [parsed];
const out = records.map(r => ({
    filename: filename,
    source_topic: srcTopic,
    ingest_timestamp: ts,
    record: r
}));
node.send([out, null]);
return null;

// csv-parse v5+: parse() returns rows as objects when columns:true.
const filename = msg.filename;
const srcTopic = msg.source_topic;
const ts = msg.ingest_timestamp;
let rows;
try {
    const text = msg.content.toString('utf8');
    rows = csvParseSync(text, {
        columns: true,
        skip_empty_lines: true,
        cast: false,
        relax_column_count: false
    });
} catch (e) {
    return [null, { payload: {
        error_type: 'parse',
        error_message: 'csv: ' + e.message,
        error_timestamp: new Date().toISOString(),
        filename: filename,
        source_topic: srcTopic
    }, filename: filename }];
}
const out = rows.map(r => ({
    filename: filename,
    source_topic: srcTopic,
    ingest_timestamp: ts,
    record: r
}));
node.send([out, null]);
return null;

const filename = msg.filename;
const srcTopic = msg.source_topic;
const ts = msg.ingest_timestamp;
// Python: content.decode('utf-8', errors='replace'). Buffer.toString('utf8')
// in Node already substitutes U+FFFD for invalid sequences — equivalent.
const raw = msg.content.toString('utf8');
const out = [{
    filename: filename,
    source_topic: srcTopic,
    ingest_timestamp: ts,
    record: { raw_content: raw }
}];
node.send([out, null]);
return null;
